"""HLD Patterns: Real-time Updates, Dealing with Contention, Multi-step Processes, Scaling Reads — 20 MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def realtime_updates_lesson() -> Lesson:
    return Lesson(id="hld-realtime-updates", number=109, title="Real-time Updates",
        focus=("WebSockets","SSE","long polling","pub/sub","push vs pull","event-driven"),
        overview="Real-time updates are asked about in nearly every interview. Know the protocols and when to use each.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("rt-1","What are the three main approaches for real-time updates?","medium",("real-time",),("REST, GraphQL, gRPC","Polling, long polling, and persistent connections (WebSockets/SSE)","TCP, UDP, QUIC","Push, pull, hybrid"),1,"Polling (wasteful), long polling (server holds request), WebSockets/SSE (persistent connection)."),
        quiz("rt-2","When should you use WebSockets over SSE?","hard",("real-time",),("Always","When you need bidirectional communication (chat, gaming) — SSE is server-to-client only","SSE is always better","They are identical"),1,"WebSockets: bidirectional (chat). SSE: unidirectional server→client (live scores, notifications)."),
        quiz("rt-3","What is the fan-out problem in real-time systems?","hard",("real-time",),("When one event must be delivered to millions of subscribers simultaneously","A caching issue","Too many fans","A database problem"),0,"Solutions: tiered fan-out, push for most users + pull for celebrity followers, connection pooling."),
        quiz("rt-4","How does Redis pub/sub work for real-time?","medium",("real-time",),("Publishers send to channels; subscribers receive messages instantly — fire-and-forget","A database transaction","A replication mode","A cache eviction"),0,"Redis pub/sub is lightweight but doesn't persist messages. Missed messages are gone."),
        quiz("rt-5","What is the difference between pub/sub and message queues for real-time?","hard",("real-time",),("Pub/sub broadcasts to all subscribers; queues deliver to one consumer per message","Queues are real-time only","Same thing","Pub/sub is slower"),0,"Pub/sub: one-to-many broadcast. Queue: one-to-one competing consumers."),
        quiz("rt-6","How do you handle millions of concurrent WebSocket connections?","hard",("real-time",),("Use HTTP instead","One server handles all","Limit to 10K connections","Distribute across many servers with sticky sessions or a presence service tracking which server handles which user"),3,"Use a presence service (Redis) to track user→server mapping. Route messages accordingly."),
        quiz("rt-7","What is a presence service?","medium",("real-time",),("A health check","An auth service","A load balancer","A system tracking which users are online and which server they're connected to"),3,"Presence services (Redis/ZooKeeper) maintain user→server mappings for routing real-time messages."),
        quiz("rt-8","How does Slack/Discord handle real-time message delivery?","hard",("real-time",),("WebSocket connections per client, gateway servers handling connections, internal message routing via pub/sub","HTTP polling","Email notifications","SMS"),0,"Gateway servers maintain WS connections. Internal pub/sub routes messages between gateways."),
        quiz("rt-9","What is connection multiplexing in real-time systems?","hard",("real-time",),("Multiple logical channels share a single physical connection (e.g., Socket.IO rooms)","A load balancing technique","A caching strategy","One connection per request"),0,"Multiplexing reduces connection overhead. One WS connection can subscribe to multiple topics/rooms."),
        quiz("rt-10","What is the heartbeat mechanism in WebSockets?","medium",("real-time",),("An encryption step","A load balancer feature","Periodic ping/pong messages to detect dead connections and keep firewalls/proxies from closing idle connections","A health check endpoint"),2,"Without heartbeats, dead connections go undetected, wasting server resources."),
        quiz("rt-11","How do you handle message ordering in distributed real-time systems?","hard",("real-time",),("TCP handles it","Use sequence numbers per channel/user, buffer out-of-order messages, and deliver in sequence","Use UDP","Messages are always ordered"),1,"Distributed systems can deliver messages out of order. Client-side reordering with sequence numbers fixes this."),
        quiz("rt-12","What is the difference between push and pull models for news feeds?","hard",("real-time",),("Push is always better","Push: precompute feeds on post (fan-out on write). Pull: compute at read time (fan-out on read)","Same thing","Pull doesn't use caching"),1,"Push for regular users. Pull for celebrities. Hybrid is best."),
        quiz("rt-13","What is event-driven architecture?","medium",("real-time",),("A caching pattern","Components communicate by producing and consuming events asynchronously via a message broker","A database architecture","Synchronous request/response"),1,"Event-driven decouples producers from consumers, enabling scalability and loose coupling."),
        quiz("rt-14","What is MQTT and when is it used?","hard",("real-time",),("A lightweight publish-subscribe protocol designed for IoT and mobile devices with unreliable networks","A REST alternative","A caching protocol","A database protocol"),0,"MQTT is lightweight (small header), supports QoS levels, and handles unreliable connections well."),
        quiz("rt-15","How does Firebase Realtime Database handle real-time sync?","hard",("real-time",),("WebSocket connections with path-based subscriptions; server pushes only changed data (diffs)","HTTP polling","gRPC streaming","REST API"),0,"Firebase sends only data diffs, reducing bandwidth. Clients subscribe to specific paths in the JSON tree."),
        quiz("rt-16","What is the challenge of real-time updates at scale?","hard",("real-time",),("UI design","Maintaining millions of persistent connections, efficient message routing, and handling connection churn","API design","Database speed"),1,"At scale: connection management, efficient pub/sub routing, and graceful handling of reconnections."),
        quiz("rt-17","What is the difference between at-most-once and at-least-once delivery in real-time?","hard",("real-time",),("At-most-once is more reliable","At-least-once loses messages","Same thing","At-most-once may lose messages; at-least-once may deliver duplicates but never loses"),3,"Chat apps need at-least-once + deduplication. Notifications can tolerate at-most-once."),
        quiz("rt-18","How do you implement typing indicators in a chat app?","medium",("real-time",),("Send ephemeral WebSocket events that are NOT persisted — they're purely transient signals","Push notifications","Store in database","HTTP polling"),0,"Typing indicators are fire-and-forget signals. No persistence needed — if missed, no harm done."),
        quiz("rt-19","What is the role of a message broker in real-time systems?","medium",("real-time",),("Decouples producers from consumers, buffers messages, and enables async processing","Database replacement","A load balancer","A cache"),0,"Brokers (Kafka, RabbitMQ, Redis Streams) provide reliability, ordering, and fan-out capabilities."),
        quiz("rt-20","How does gRPC server streaming work for real-time?","hard",("real-time",),("Same as WebSockets","A database feature","A REST pattern","Server sends a stream of messages over a single HTTP/2 connection; client receives them sequentially"),3,"gRPC streaming: server opens a response stream. Efficient binary serialization via Protobuf."),
    ))

def contention_lesson() -> Lesson:
    return Lesson(id="hld-contention", number=110, title="Dealing with Contention",
        focus=("optimistic locking","pessimistic locking","CAS","distributed locks","hot partitions"),
        overview="Contention is the enemy of scale. Know when to lock, when to avoid locks, and how to design around hotspots.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("cnt-1","What is optimistic concurrency control?","medium",("contention",),("Always use locks","Assume no conflict; check version at commit time and retry if conflict detected","A database index","A caching strategy"),1,"Optimistic works well with low contention. Higher throughput than pessimistic locking."),
        quiz("cnt-2","What is pessimistic locking?","medium",("contention",),("A read-only strategy","A caching technique","No locking","Lock the resource upfront before any operation to prevent conflicts"),3,"SELECT FOR UPDATE in SQL. Prevents conflicts but reduces throughput due to lock contention."),
        quiz("cnt-3","What is compare-and-swap (CAS)?","hard",("contention",),("A compression method","An atomic operation: read current value, compare with expected, swap only if match","A sorting algorithm","A hashing technique"),1,"CAS is the foundation of lock-free data structures. Redis WATCH/MULTI implements CAS semantics."),
        quiz("cnt-4","How do you handle ticket purchasing contention (Ticketmaster)?","hard",("contention",),("No locking needed","Let them fight","Queue all buyers","Temporary seat reservation with TTL + atomic inventory decrement (Redis DECR or DB row lock)"),3,"Reserve with TTL (10 min), decrement atomically, release on timeout or payment completion."),
        quiz("cnt-5","What is the hot partition problem?","hard",("contention",),("A network issue","A temperature issue","One partition/shard receiving disproportionate traffic, becoming a bottleneck","A caching problem"),2,"Solutions: add entropy to key (salting), split the hot key, or use write-behind buffering."),
        quiz("cnt-6","What is distributed locking?","hard",("contention",),("File locking","Coordinating mutual exclusion across multiple nodes using a distributed lock service","A load balancer feature","A database lock"),1,"Implemented via Redis (Redlock), ZooKeeper, or etcd. More complex and less reliable than local locks."),
        quiz("cnt-7","What is the Redlock algorithm?","hard",("contention",),("A Redis command","Martin Kleppmann's critique: acquire locks on N/2+1 independent Redis instances with a global timeout","A consensus protocol","A hash algorithm"),1,"Redlock attempts distributed locking but is controversial — clock drift and GC pauses can break safety."),
        quiz("cnt-8","What is idempotency and how does it help with contention?","hard",("contention",),("A sorting algorithm","A caching technique","A locking strategy","Making operations safe to retry — if contention causes failure, the client retries without side effects"),3,"Idempotency keys let servers detect duplicates, making retry-on-conflict safe."),
        quiz("cnt-9","How do you handle the counter problem at scale?","hard",("contention",),("Lock the counter","Use a single DB row","Single counter","Shard the counter across N shards, increment random shard, sum all shards for total (approximate)"),3,"Single counters don't scale. Sharded counters trade accuracy for throughput."),
        quiz("cnt-10","What is the leaky bucket algorithm for handling contention?","hard",("contention",),("Requests flow in at any rate but are processed at a fixed rate — excess requests are dropped or queued","A caching strategy","A locking mechanism","A data structure"),0,"Leaky bucket smooths bursty traffic. Unlike token bucket, it enforces a strict constant output rate."),
        quiz("cnt-11","How does Stripe handle payment contention?","hard",("contention",),("No special handling","Queue all payments","Idempotency keys + optimistic locking + event sourcing ensure exactly-once payment processing","Lock the entire database"),2,"Each payment has a unique idempotency key. Retries check the key and return the existing result."),
        quiz("cnt-12","What is write skew and how do you prevent it?","hard",("contention",),("A UI issue","Two transactions read overlapping data, make decisions, and write — each valid individually but together violate a constraint","A read problem","A caching issue"),1,"Example: two doctors both see 3 on-call, each decides to remove themselves, leaving 1. Fix: serializable isolation."),
        quiz("cnt-13","What is a semaphore vs a mutex?","medium",("contention",),("Mutex allows one holder; semaphore allows N concurrent holders (counting semaphore)","Same thing","Semaphore is faster","Mutex allows many holders"),0,"Use mutex for exclusive access. Use semaphore to limit concurrency (e.g., max 10 DB connections)."),
        quiz("cnt-14","How do you handle auction bid contention?","hard",("contention",),("Lock the entire auction","No locking","Queue all bids","Atomic compare-and-swap: read current highest → compare → update only if new bid is higher"),3,"CAS pattern: ensure only the highest valid bid wins without race conditions."),
        quiz("cnt-15","What is the thundering herd problem in locking?","hard",("contention",),("A noise issue","A network problem","A database issue","When a lock is released, all waiting threads wake up and compete for it, causing CPU spikes"),3,"Solution: use fair locks (FIFO queue) or exponential backoff with jitter."),
        quiz("cnt-16","What is a read-write lock?","medium",("contention",),("A database feature","A file lock","A network protocol","Allows multiple concurrent readers OR a single writer — improves throughput for read-heavy workloads"),3,"RW locks: many readers share access. Writers get exclusive access. Readers block only during writes."),
        quiz("cnt-17","How does MVCC handle contention?","hard",("contention",),("A replication strategy","It doesn't","Each transaction sees a snapshot of the data, allowing concurrent reads/writes without blocking","A locking mechanism"),2,"MVCC: readers don't block writers, writers don't block readers. Each sees a consistent snapshot."),
        quiz("cnt-18","What is exponential backoff with jitter?","medium",("contention",),("A sleep schedule","A constant retry","A timeout strategy","Retry with exponentially increasing delays plus random jitter to spread retries and reduce contention"),3,"Wait = min(cap, base × 2^attempt) + random_jitter. Prevents synchronized retry storms."),
        quiz("cnt-19","What is the inventory reservation pattern?","hard",("contention",),("Lock all inventory","Counting stock","Pre-purchase all items","Reserve items with a TTL during checkout; release if payment fails or times out"),3,"Prevents overselling while allowing concurrent checkouts. TTL-based reservations auto-expire."),
        quiz("cnt-20","What is the saga pattern for handling distributed contention?","hard",("contention",),("A long transaction","A consensus algorithm","A locking protocol","A sequence of local transactions with compensating actions — avoids distributed locks entirely"),3,"Sagas replace distributed locks with local transactions + compensations. No 2PC blocking needed."),
    ))

def multistep_lesson() -> Lesson:
    return Lesson(id="hld-multistep", number=111, title="Multi-step Processes",
        focus=("sagas","2PC","event sourcing","outbox pattern","compensating actions","workflow engines"),
        overview="Distributed transactions are inevitable. Know Sagas, 2PC, event sourcing, and when to use each.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("ms-1","What is the Saga pattern?","hard",("saga",),("A long DB transaction","A type of 2PC","A caching pattern","A sequence of local transactions where each step has a compensating action for rollback"),3,"Sagas handle distributed transactions without 2PC. Each step can be undone independently."),
        quiz("ms-2","Choreography vs orchestration sagas?","hard",("saga",),("Choreography uses a coordinator","Orchestration is decentralized","No difference","Choreography: services react to events. Orchestration: a central coordinator directs steps"),3,"Choreography is more decoupled. Orchestration is centralized and easier to reason about."),
        quiz("ms-3","What is two-phase commit (2PC)?","hard",("distributed",),("A load balancing algorithm","A caching technique","A database index","Prepare phase (all vote) → commit phase (all commit or all abort). Atomic but blocking"),3,"2PC guarantees atomicity but blocks if coordinator fails. Avoided in microservices."),
        quiz("ms-4","Why is 2PC problematic in microservices?","hard",("distributed",),("It doesn't work","It's too fast","It's too simple","Blocking nature, coordinator SPOF, high latency, and tight coupling between services"),3,"2PC blocks all participants if coordinator fails. Sagas are preferred for loose coupling."),
        quiz("ms-5","What is event sourcing?","hard",("event-sourcing",),("Logging errors","A message queue","Database sharding","Storing all state changes as an immutable event log instead of just current state"),3,"Event sourcing gives audit trails, time travel, and ability to rebuild state from events."),
        quiz("ms-6","What is the outbox pattern?","hard",("patterns",),("A caching strategy","An email pattern","Write events to an outbox table in the same DB transaction, then publish asynchronously","A logging technique"),2,"Outbox ensures atomicity between DB writes and event publishing. Avoids dual-write problems."),
        quiz("ms-7","What is a compensating transaction?","medium",("saga",),("A refund","An action that undoes the effect of a previous transaction step (e.g., cancel booking, refund payment)","A database rollback","A cache clear"),1,"In Sagas, compensations undo completed steps when a later step fails."),
        quiz("ms-8","What is the CDC (Change Data Capture) approach to multi-step?","hard",("patterns",),("Backing up data","A migration tool","A caching strategy","Streaming DB changes as events via the WAL, enabling downstream systems to react asynchronously"),3,"CDC (Debezium) turns DB changes into events without modifying application code."),
        quiz("ms-9","How do you handle partial failures in a Saga?","hard",("saga",),("Lock all services","Execute compensating transactions for completed steps in reverse order","Ignore them","Retry everything"),1,"If step 3 of 5 fails: compensate step 2, compensate step 1. Each compensation must be idempotent."),
        quiz("ms-10","What is the transactional outbox implementation?","hard",("patterns",),("Write to outbox table in same DB transaction as business data; a poller/CDC reads outbox and publishes events","A cache pattern","A file system","A message queue"),0,"Guarantees at-least-once event publishing without distributed transactions."),
        quiz("ms-11","What are the challenges of event sourcing?","hard",("event-sourcing",),("No challenges","It's too simple","Only works for small data","Schema evolution, event versioning, replay performance, and eventual consistency of read models"),3,"Event stores grow forever. Snapshots help. Event schema changes require migration strategies."),
        quiz("ms-12","What is a process manager in orchestration sagas?","hard",("saga",),("A Unix process","A load balancer","A stateful coordinator that tracks saga progress, sends commands, and handles responses/timeouts","A database"),2,"The process manager maintains saga state and drives the workflow forward."),
        quiz("ms-13","What is idempotency's role in multi-step processes?","hard",("saga",),("A UI concern","Every step must be idempotent so that retries after partial failures don't cause side effects","Not relevant","A performance optimization"),1,"Without idempotency, retrying a failed saga step could duplicate charges, bookings, etc."),
        quiz("ms-14","What is the dead letter queue in multi-step processes?","medium",("patterns",),("A backup queue","A logging mechanism","A deleted queue","Where messages that fail processing after max retries are sent for investigation"),3,"DLQs prevent poison messages from blocking the pipeline."),
        quiz("ms-15","How do you ensure exactly-once processing in sagas?","hard",("saga",),("Impossible","Use 2PC","Use TCP","At-least-once delivery + idempotent consumers = effectively-once processing"),3,"True exactly-once is nearly impossible. Idempotent handlers make duplicates harmless."),
        quiz("ms-16","What is the difference between choreography and orchestration in reliability?","hard",("saga",),("Choreography is more reliable","Orchestration is unreliable","No difference","Choreography is harder to debug (implicit flow); orchestration provides clear visibility and error handling"),3,"Choreography: implicit flow in event subscriptions. Orchestration: explicit, traceable state machine."),
        quiz("ms-17","What is a workflow engine (e.g., Temporal, Cadence)?","hard",("patterns",),("A load balancer","A message queue","A CI/CD tool","A platform for defining, executing, and recovering durable multi-step workflows with built-in retry/state management"),3,"Temporal/Cadence handle timeouts, retries, compensations, and state persistence automatically."),
        quiz("ms-18","What is the try-confirm-cancel (TCC) pattern?","hard",("patterns",),("A caching pattern","Same as 2PC","A locking mechanism","A reservation pattern: Try (reserve), Confirm (commit), or Cancel (release) — each service manages its own resources"),3,"TCC is like Saga but with explicit reservation. Each service locks resources during Try phase."),
        quiz("ms-19","How does event sourcing relate to CQRS?","hard",("event-sourcing",),("Events drive the write model; read models are projections of events optimized for queries — naturally complementary","CQRS replaces event sourcing","They are identical","No relation"),0,"Event sourcing provides the event log. CQRS projects it into read-optimized materialized views."),
        quiz("ms-20","What is the at-least-once delivery guarantee and why is it the practical choice?","hard",("patterns",),("All guarantees are equal","At-most-once may lose messages; exactly-once is nearly impossible; at-least-once + idempotent consumers is practical","Exactly-once is easier","At-most-once is preferred"),1,"At-least-once is achievable with acks/retries. Combined with idempotent processing, it's effectively-once."),
    ))

def scaling_reads_lesson() -> Lesson:
    return Lesson(id="hld-scaling-reads", number=112, title="Scaling Reads",
        focus=("read replicas","caching","CQRS","CDN","denormalization","materialized views"),
        overview="Most applications are read-heavy. Know the full toolkit for scaling reads efficiently.",
        patterns=(), badge="HLD Pattern", tasks=(
        quiz("sr-1","What is the most common approach to scaling reads?","easy",("scaling-reads",),("More indexes","Add read replicas — write to primary, read from replicas","Faster CPU","Bigger database"),1,"Read replicas distribute read load. Works well for read-heavy workloads with tolerable replication lag."),
        quiz("sr-2","What is CQRS?","hard",("scaling-reads",),("Command Query Responsibility Segregation — separate read and write models optimized independently","A database type","A caching strategy","A load balancing technique"),0,"CQRS: write model can be normalized for consistency; read model can be denormalized for speed."),
        quiz("sr-3","How does denormalization help read performance?","medium",("scaling-reads",),("It doesn't","Pre-joins data into a single read-optimized structure, eliminating JOIN queries at read time","Reduces storage","Improves write speed"),1,"Denormalization trades write complexity and storage for dramatically faster reads."),
        quiz("sr-4","What is a materialized view?","medium",("scaling-reads",),("A cache","An index","A precomputed query result stored as a table, updated periodically or on write","A regular view"),2,"Materialized views: precomputed aggregations/JOINs. Great for dashboards and analytics."),
        quiz("sr-5","What is the replication lag problem?","hard",("scaling-reads",),("A network issue","No problem","A caching problem","Time delay between a write on the primary and when it appears on replicas, causing stale reads"),3,"Solution: read-your-own-writes by routing the writing user to the primary for subsequent reads."),
        quiz("sr-6","When is caching better than read replicas?","medium",("scaling-reads",),("Never","When data changes frequently","When you need sub-millisecond reads, data access patterns follow 80/20, and slight staleness is OK","Always"),2,"Cache: μs latency, handles hot data well. Replicas: ms latency, serve all data."),
        quiz("sr-7","What is the query result cache pattern?","medium",("scaling-reads",),("Database cache","A view","An index","Cache the full result of expensive queries using the query+params as the cache key"),3,"Cache key = hash(query + params). Invalidate when underlying data changes."),
        quiz("sr-8","How does CDN help scale reads?","easy",("scaling-reads",),("API routing","Database replication","Caches static content at edge locations near users, reducing origin server load","Database scaling"),2,"CDNs serve images, CSS, JS, and even API responses from edge — reducing latency and origin load."),
        quiz("sr-9","What is read-through caching in the context of scaling reads?","medium",("scaling-reads",),("The cache transparently fetches from DB on miss — application only talks to the cache","A write strategy","Same as cache-aside","A replication mode"),0,"Read-through simplifies application code — the cache handles the DB interaction."),
        quiz("sr-10","What is the fan-out on read approach?","hard",("scaling-reads",),("Pre-computing feeds","Computing the result at read time by querying and aggregating from multiple sources","A write approach","A caching strategy"),1,"Fan-out on read: cheaper writes but more expensive reads. Good for data that's written by celebrities."),
        quiz("sr-11","How do you handle search scaling for reads?","hard",("scaling-reads",),("Use a dedicated search engine (Elasticsearch) as a denormalized read model","Use the main database","Increase CPU","Use more indexes"),0,"Elasticsearch as a read-optimized projection: sync data via CDC, serve search/filter queries."),
        quiz("sr-12","What is pre-computation for scaling reads?","medium",("scaling-reads",),("Real-time calculation","Compute expensive results offline and store them for fast retrieval (e.g., recommendation scores, leaderboards)","A network optimization","A caching issue"),1,"Pre-compute: leaderboards, recommendation scores, trending topics. Serve from cache/fast store."),
        quiz("sr-13","How do read replicas handle failover?","hard",("scaling-reads",),("They don't","Promote a replica to primary when the primary fails; other replicas switch to the new primary","Use the cache instead","Auto-restart the primary"),1,"Failover promotes a replica. Some systems (RDS Multi-AZ) handle this automatically."),
        quiz("sr-14","What is the N+1 read problem and how does it affect scaling?","hard",("scaling-reads",),("Fetching a list (1 query) then N individual queries for related data — turns 1 query into N+1","A network issue","A replication lag","A caching problem"),0,"N+1 multiplies database load. Fix with JOINs, batch fetching, or DataLoader pattern."),
        quiz("sr-15","What is edge computing for read scaling?","hard",("scaling-reads",),("A caching protocol","A database feature","Desktop computing","Processing and serving data at edge locations closer to users, reducing round-trip latency"),3,"Edge computing (Cloudflare Workers, Lambda@Edge): run logic at CDN edge, not just cache content."),
        quiz("sr-16","How do you scale read-heavy time-series queries?","hard",("scaling-reads",),("More indexes","Bigger machine","Single database","Use time-based partitioning + downsampling + tiered storage (hot/warm/cold)"),3,"Recent data in fast store (SSD), older data downsampled and moved to cheaper storage."),
        quiz("sr-17","What is data locality optimization for reads?","medium",("scaling-reads",),("Storing all data together","Storing related data that's frequently accessed together physically close (same partition, same node)","A caching strategy","A network optimization"),1,"Co-locating related data reduces cross-partition reads and improves cache utilization."),
        quiz("sr-18","When should you NOT add read replicas?","medium",("scaling-reads",),("Never","When using NoSQL","When write-heavy workload means replicas can't keep up, or consistency requirements don't tolerate lag","When reads are high"),2,"Write-heavy workloads: replicas lag behind, serving stale data. Consider caching or sharding instead."),
        quiz("sr-19","What is a query plan cache?","hard",("scaling-reads",),("An index cache","A disk cache","Database caches parsed/optimized query plans to avoid re-planning identical queries","A result cache"),2,"Plan caching (prepared statements) eliminates query parsing overhead for repeated queries."),
        quiz("sr-20","How does pagination help scale reads?","easy",("scaling-reads",),("It doesn't","Improves consistency","Breaks large result sets into pages, reducing memory usage and response size per request","Speeds up writes"),2,"Without pagination, returning 1M rows crashes clients and overwhelms servers."),
    ))
